---doh.go---
     1	package dnsresolve
     2	
     3	import (
     4		"bytes"
     5		"context"
     6		"crypto/tls"
     7		"crypto/x509"
     8		"errors"
     9		"fmt"
    10		"io"
    11		"net"
    12		"net/http"
    13		"net/netip"
    14		"net/url"
    15		"strings"
    16		"time"
    17	
    18		"golang.org/x/net/dns/dnsmessage"
    19	)
    20	
    21	// dohMediaType is the RFC 8484 wire-format media type for both the request
    22	// body and the expected response body.
    23	const dohMediaType = "application/dns-message"
    24	
    25	// dohTimeout bounds a single DoH POST round trip (request send + response
    26	// read). It applies via http.Client.Timeout in addition to whatever deadline
    27	// the caller's context already carries.
    28	const dohTimeout = 5 * time.Second
    29	
    30	// DoHResolver resolves hostnames via DNS-over-HTTPS (RFC 8484): it encodes A
    31	// and AAAA queries with golang.org/x/net/dns/dnsmessage, POSTs each to a
    32	// configured DoH URL, and extracts the answer addrs and minimum TTL.
    33	//
    34	// Residual leak: the DoH provider (and any network observer) sees the TLS
    35	// SNI of the DoH URL's host and the timing/size of each request — DoH hides
    36	// the query *content* from on-path observers, not the fact that this host is
    37	// talking to that DoH provider.
    38	type DoHResolver struct {
    39		url    string
    40		client *http.Client
    41	}
    42	
    43	var _ Resolver = (*DoHResolver)(nil)
    44	
    45	// NewDoHResolver returns a Resolver that POSTs DNS-over-HTTPS queries to
    46	// rawURL (which must be an https:// URL). Certificate trust uses the
    47	// platform's standard root CA store — there is no production knob to disable
    48	// certificate verification.
    49	func NewDoHResolver(rawURL string) (*DoHResolver, error) {
    50		return newDoHResolver(rawURL, nil)
    51	}
    52	
    53	// newDoHResolver is the unexported constructor seam: a non-nil roots pool
    54	// overrides the platform trust store with roots, for injecting a test CA
    55	// (e.g. from httptest.NewTLSServer) — it exists ONLY for tests in this
    56	// package. Production code always goes through NewDoHResolver, which passes
    57	// roots=nil and gets tls.Config's default (the system pool).
    58	func newDoHResolver(rawURL string, roots *x509.CertPool) (*DoHResolver, error) {
    59		parsed, err := url.Parse(rawURL)
    60		if err != nil {
    61			return nil, fmt.Errorf("dnsresolve: invalid DoH URL %q: %w", rawURL, err)
    62		}
    63		if parsed.Scheme != "https" {
    64			return nil, fmt.Errorf("dnsresolve: DoH URL %q must use https, got scheme %q", rawURL, parsed.Scheme)
    65		}
    66	
    67		transport := &http.Transport{
    68			// No proxy surprise: never route DoH queries through an
    69			// environment-configured (HTTP_PROXY/HTTPS_PROXY) proxy — a DoH
    70			// resolver silently redirected through an unexpected intermediary
    71			// would defeat the point of choosing a specific trusted provider.
    72			Proxy: nil,
    73			TLSClientConfig: &tls.Config{
    74				RootCAs:    roots,
    75				MinVersion: tls.VersionTLS12,
    76			},
    77			// HTTP/2 ok: Go only auto-negotiates h2 over a custom
    78			// TLSClientConfig when this is set explicitly.
    79			ForceAttemptHTTP2: true,
    80		}
    81	
    82		return &DoHResolver{
    83			url: rawURL,
    84			client: &http.Client{
    85				Transport: transport,
    86				Timeout:   dohTimeout,
    87			},
    88		}, nil
    89	}
    90	
    91	// Lookup implements Resolver. It queries A and AAAA for host and merges the
    92	// results; a family that answers NXDOMAIN is tolerated as long as the other
    93	// family answers. Any other per-family error (transport failure, non-200,
    94	// malformed response) fails the whole lookup.
    95	func (d *DoHResolver) Lookup(ctx context.Context, host string) ([]netip.Addr, time.Duration, bool, error) {
    96		var (
    97			addrs      []netip.Addr
    98			minTTL     time.Duration
    99			haveTTL    bool
   100			haveAnswer bool
   101			nxdomain   error
   102		)
   103	
   104		for _, qtype := range [...]dnsmessage.Type{dnsmessage.TypeA, dnsmessage.TypeAAAA} {
   105			famAddrs, famMinTTL, famHaveTTL, err := d.queryFamily(ctx, host, qtype)
   106			if err != nil {
   107				var nx *NXDomainError
   108				if errors.As(err, &nx) {
   109					nxdomain = err
   110					continue
   111				}
   112				return nil, 0, false, err
   113			}
   114	
   115			haveAnswer = true
   116			addrs = append(addrs, famAddrs...)
   117			if famHaveTTL && (!haveTTL || famMinTTL < minTTL) {
   118				minTTL = famMinTTL
   119				haveTTL = true
   120			}
   121		}
   122	
   123		if !haveAnswer {
   124			if nxdomain != nil {
   125				return nil, 0, false, nxdomain
   126			}
   127			return nil, 0, false, fmt.Errorf("dnsresolve: DoH lookup for %q returned no answers", host)
   128		}
   129	
   130		return addrs, minTTL, haveTTL, nil
   131	}
   132	
   133	// queryFamily runs a single A or AAAA query over DoH.
   134	func (d *DoHResolver) queryFamily(ctx context.Context, host string, qtype dnsmessage.Type) ([]netip.Addr, time.Duration, bool, error) {
   135		query, err := buildDoHQuery(host, qtype)
   136		if err != nil {
   137			return nil, 0, false, fmt.Errorf("dnsresolve: encoding DoH query for %q: %w", host, err)
   138		}
   139	
   140		req, err := http.NewRequestWithContext(ctx, http.MethodPost, d.url, bytes.NewReader(query))
   141		if err != nil {
   142			return nil, 0, false, fmt.Errorf("dnsresolve: building DoH request to %s: %w", d.url, err)
   143		}
   144		req.Header.Set("Content-Type", dohMediaType)
   145		req.Header.Set("Accept", dohMediaType)
   146	
   147		resp, err := d.client.Do(req)
   148		if err != nil {
   149			if isTimeoutErr(err) {
   150				return nil, 0, false, &TimeoutError{URL: d.url, Err: err}
   151			}
   152			return nil, 0, false, fmt.Errorf("dnsresolve: DoH POST to %s failed: %w", d.url, err)
   153		}
   154		defer resp.Body.Close()
   155	
   156		if resp.StatusCode != http.StatusOK {
   157			return nil, 0, false, &StatusError{URL: d.url, StatusCode: resp.StatusCode}
   158		}
   159	
   160		body, err := io.ReadAll(resp.Body)
   161		if err != nil {
   162			if isTimeoutErr(err) {
   163				return nil, 0, false, &TimeoutError{URL: d.url, Err: err}
   164			}
   165			return nil, 0, false, &MalformedResponseError{URL: d.url, Err: err}
   166		}
   167	
   168		return parseDoHResponse(d.url, body, host, qtype)
   169	}
   170	
   171	// buildDoHQuery packs a single-question A/AAAA query. Per RFC 8484 SS4.1, it
   172	// uses a DNS ID of 0 to maximize HTTP cache friendliness.
   173	func buildDoHQuery(host string, qtype dnsmessage.Type) ([]byte, error) {
   174		name, err := dnsmessage.NewName(fqdn(host))
   175		if err != nil {
   176			return nil, err
   177		}
   178		msg := dnsmessage.Message{
   179			Header: dnsmessage.Header{
   180				ID:               0,
   181				RecursionDesired: true,
   182			},
   183			Questions: []dnsmessage.Question{
   184				{Name: name, Type: qtype, Class: dnsmessage.ClassINET},
   185			},
   186		}
   187		return msg.Pack()
   188	}
   189	
   190	// parseDoHResponse unpacks body and extracts the addrs and minimum TTL of
   191	// the qtype records it contains.
   192	func parseDoHResponse(dohURL string, body []byte, host string, qtype dnsmessage.Type) ([]netip.Addr, time.Duration, bool, error) {
   193		var msg dnsmessage.Message
   194		if err := msg.Unpack(body); err != nil {
   195			return nil, 0, false, &MalformedResponseError{URL: dohURL, Err: err}
   196		}
   197	
   198		if msg.RCode == dnsmessage.RCodeNameError {
   199			return nil, 0, false, &NXDomainError{URL: dohURL, Host: host}
   200		}
   201		if msg.RCode != dnsmessage.RCodeSuccess {
   202			return nil, 0, false, &MalformedResponseError{URL: dohURL, Err: fmt.Errorf("response RCode %v", msg.RCode)}
   203		}
   204	
   205		var addrs []netip.Addr
   206		var minTTL time.Duration
   207		haveTTL := false
   208		for _, ans := range msg.Answers {
   209			if ans.Header.Class != dnsmessage.ClassINET {
   210				continue
   211			}
   212	
   213			var addr netip.Addr
   214			switch res := ans.Body.(type) {
   215			case *dnsmessage.AResource:
   216				if qtype != dnsmessage.TypeA {
   217					continue
   218				}
   219				addr = netip.AddrFrom4(res.A)
   220			case *dnsmessage.AAAAResource:
   221				if qtype != dnsmessage.TypeAAAA {
   222					continue
   223				}
   224				addr = netip.AddrFrom16(res.AAAA)
   225			default:
   226				continue
   227			}
   228	
   229			addrs = append(addrs, addr)
   230			ttl := time.Duration(ans.Header.TTL) * time.Second
   231			if !haveTTL || ttl < minTTL {
   232				minTTL = ttl
   233				haveTTL = true
   234			}
   235		}
   236	
   237		return addrs, minTTL, haveTTL, nil
   238	}
   239	
   240	// fqdn returns host with a trailing dot, as dnsmessage.Name requires.
   241	func fqdn(host string) string {
   242		if strings.HasSuffix(host, ".") {
   243			return host
   244		}
   245		return host + "."
   246	}
   247	
   248	// isTimeoutErr reports whether err represents a request that exceeded its
   249	// deadline (context deadline or http.Client/net.Dialer timeout).
   250	func isTimeoutErr(err error) bool {
   251		var netErr net.Error
   252		if errors.As(err, &netErr) && netErr.Timeout() {
   253			return true
   254		}
   255		return errors.Is(err, context.DeadlineExceeded)
   256	}
   257	
   258	// StatusError reports a DoH provider responding with a non-200 HTTP status.
   259	type StatusError struct {
   260		URL        string
   261		StatusCode int
   262	}
   263	
   264	func (e *StatusError) Error() string {
   265		return fmt.Sprintf("dnsresolve: DoH %s returned HTTP status %d", e.URL, e.StatusCode)
   266	}
   267	
   268	// MalformedResponseError reports a DoH response body that failed to decode
   269	// as a valid DNS message, or that decoded to an unexpected RCode.
   270	type MalformedResponseError struct {
   271		URL string
   272		Err error
   273	}
   274	
   275	func (e *MalformedResponseError) Error() string {
   276		return fmt.Sprintf("dnsresolve: DoH %s returned a malformed response: %v", e.URL, e.Err)
   277	}
   278	
   279	func (e *MalformedResponseError) Unwrap() error { return e.Err }
   280	
   281	// TimeoutError reports a DoH request that did not complete within its
   282	// deadline.
   283	type TimeoutError struct {
   284		URL string
   285		Err error
   286	}
   287	
   288	func (e *TimeoutError) Error() string {
   289		return fmt.Sprintf("dnsresolve: DoH %s request timed out: %v", e.URL, e.Err)
   290	}
   291	
   292	func (e *TimeoutError) Unwrap() error { return e.Err }
   293	
   294	// NXDomainError reports a DoH provider answering NXDOMAIN for one address
   295	// family. Lookup tolerates this as long as the other family answers.
   296	type NXDomainError struct {
   297		URL  string
   298		Host string
   299	}
   300	
   301	func (e *NXDomainError) Error() string {
   302		return fmt.Sprintf("dnsresolve: DoH %s: no such host %q", e.URL, e.Host)
   303	}

