245		// `defer close(blockCh)` registered before `defer srv.Close()` would
246		// run second, i.e. too late, and deadlock the test).
247		defer func() {
248			close(blockCh)
249			srv.Close()
250		}()
251	
252		r := newDoHTestResolver(t, srv, "/dns-query")
253	
254		ctx, cancel := context.WithTimeout(context.Background(), 50*time.Millisecond)
255		defer cancel()
256	
257		_, _, _, err := r.Lookup(ctx, "example.com")
258		if err == nil {
259			t.Fatal("Lookup: expected timeout error, got nil")
260		}
261		var timeoutErr *TimeoutError
262		if !errors.As(err, &timeoutErr) {
263			t.Fatalf("Lookup: err = %v (%T), want *TimeoutError", err, err)
264		}
265	}
266	
267	func TestNewDoHResolverRejectsNonHTTPS(t *testing.T) {
268		if _, err := NewDoHResolver("http://example.com/dns-query"); err == nil {
269			t.Fatal("NewDoHResolver(http://...): expected error, got nil")
270		}
271	}

